import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { Plus, FolderKanban, ArrowRight, X } from 'lucide-react';
import toast from 'react-hot-toast';
import { projectsApi } from '../services/api';
import { formatRelativeTime, getErrorMessage, truncate } from '../utils/helpers';

function CreateProjectModal({ onClose, onCreated }) {
  const [form, setForm] = useState({ name: '', key: '', description: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.name || !form.key) return toast.error('Name and key are required');
    setLoading(true);
    try {
      const { data } = await projectsApi.create(form);
      toast.success('Project created!');
      onCreated(data.project);
    } catch (err) {
      toast.error(getErrorMessage(err));
    } finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <div className="modal-header">
          <span className="modal-title">New Project</span>
          <button className="btn btn-ghost btn-icon" onClick={onClose}><X size={16} /></button>
        </div>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">Project Name *</label>
            <input className="input" placeholder="e.g. Mobile App Redesign" value={form.name}
              onChange={e => {
                const name = e.target.value;
                setForm(f => ({
                  ...f, name,
                  key: name.split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 6),
                }));
              }} />
          </div>
          <div className="form-group">
            <label className="form-label">Project Key *</label>
            <input className="input" placeholder="e.g. MAR" value={form.key}
              onChange={e => setForm(f => ({ ...f, key: e.target.value.toUpperCase().slice(0, 10) }))} />
            <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Short code used to prefix task IDs (e.g. MAR-1)</span>
          </div>
          <div className="form-group">
            <label className="form-label">Description</label>
            <textarea className="input" rows={3} placeholder="What's this project about?"
              value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
          </div>
          <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'flex-end', marginTop: '1rem' }}>
            <button type="button" className="btn btn-secondary" onClick={onClose}>Cancel</button>
            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? <span className="spinner" /> : <><Plus size={15} /> Create Project</>}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default function ProjectsPage() {
  const navigate = useNavigate();
  const [projects, setProjects] = useState([]);
  const [loading, setLoading]   = useState(true);
  const [showModal, setShowModal] = useState(false);

  const load = useCallback(() => {
    projectsApi.list({ limit: 50 })
      .then(({ data }) => setProjects(data.data || []))
      .catch(() => toast.error('Failed to load projects'))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => { load(); }, [load]);

  return (
    <div>
      <div className="page-header">
        <div>
          <h1>Projects</h1>
          <p>All your workspaces in one place</p>
        </div>
        <button className="btn btn-primary" onClick={() => setShowModal(true)}>
          <Plus size={15} /> New Project
        </button>
      </div>

      {loading ? (
        <div className="empty-state"><div className="spinner spinner-lg" /></div>
      ) : projects.length === 0 ? (
        <div className="empty-state">
          <FolderKanban size={48} />
          <h3>No projects yet</h3>
          <p>Create your first project to start managing tasks</p>
          <button className="btn btn-primary" onClick={() => setShowModal(true)}>
            <Plus size={14} /> Create Project
          </button>
        </div>
      ) : (
        <div className="grid-3">
          {projects.map(project => (
            <div key={project._id} className="card card-hover" style={{ cursor: 'pointer' }}
              onClick={() => navigate(`/projects/${project._id}`)}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.75rem' }}>
                <div>
                  <span style={{
                    fontSize: '0.68rem', fontWeight: 700,
                    background: 'var(--accent-dim)', color: 'var(--accent)',
                    padding: '2px 7px', borderRadius: 4, marginBottom: 6, display: 'inline-block',
                  }}>{project.key}</span>
                  <h3 style={{ fontSize: '1rem', fontWeight: 700 }}>{project.name}</h3>
                </div>
                <ArrowRight size={15} style={{ color: 'var(--text-muted)', marginTop: 4 }} />
              </div>
              {project.description && (
                <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginBottom: '1rem', lineHeight: 1.55 }}>
                  {truncate(project.description, 100)}
                </p>
              )}
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 'auto' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                  <div className="avatar avatar-sm">{project.owner?.name?.[0]?.toUpperCase()}</div>
                  <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{project.owner?.name}</span>
                </div>
                <span style={{
                  fontSize: '0.68rem', fontWeight: 600,
                  color: project.status === 'ACTIVE' ? 'var(--green)' : 'var(--text-muted)',
                }}>{project.status}</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {showModal && (
        <CreateProjectModal
          onClose={() => setShowModal(false)}
          onCreated={(p) => { setProjects(prev => [p, ...prev]); setShowModal(false); }}
        />
      )}
    </div>
  );
}
